class Counter {
    private int count = 0;

    // Synchronized method (locks on this)
    public synchronized void increment() {
        count++;
    }

    // Synchronized block
    public void decrement() {
        synchronized (this) {
            count--;
        }
    }

    // Synchronized static method (locks on the Class object)
    private static int total = 0;
    public static synchronized void addTotal(int n) {
        total += n;
    }

    // Locking on an arbitrary object
    private final Object lock = new Object();
    public void safeOp() {
        synchronized (lock) {
            // Locks on the lock object
            count++;
        }
    }
}

// UnsafeCounter class definition
class UnsafeCounter {
    private int count = 0;
    // increment method definition
    public void increment() { count++; } // Not synchronized!
    // getCount method definition
    public int getCount() { return count; }
}

// SafeCounter class definition
class SafeCounter {
    private int count = 0;
    public synchronized void increment() { count++; } // Synchronized
    public synchronized int getCount() { return count; }
}

