class Reentrant {
    public synchronized void methodA() {
        System.out.println("A");
        methodB(); // Can call another synchronized method on the same object
    }

    public synchronized void methodB() {
        System.out.println("B");
    }
}

// Calling methodA() acquires the lock on this
// When methodA() calls methodB(), the lock is already held and can be reacquired
Reentrant r = new Reentrant();
new Thread(() -> r.methodA()).start();
// Output: A B

