import java.util.concurrent.ConcurrentHashMap;

ConcurrentHashMap<String, Integer> map = new ConcurrentHashMap<>();
map.put("A", 1);
map.put("B", 2);

// Atomic operations
map.putIfAbsent("C", 3);  // Add only if key C does not exist
map.replace("A", 1, 10);  // Replace with 10 only if the value is 1
map.compute("B", (k, v) -> v + 100); // Atomically compute and update

System.out.println(map); // {A=10, B=102, C=3}

// null is not allowed
try {
    map.put("D", null); // NullPointerException
} catch (NullPointerException e) {
    System.out.println("null not allowed");
}

// Modification during iteration is safe
map.forEach((k, v) -> {
    if (v > 50) map.remove(k); // No ConcurrentModificationException
});

import java.util.concurrent.CopyOnWriteArrayList;
import java.util.Iterator;

CopyOnWriteArrayList<String> list = new CopyOnWriteArrayList<>();
list.add("A");
