import java.util.concurrent.*;

ExecutorService pool = Executors.newFixedThreadPool(2);
pool.submit(() -> {
    try { Thread.sleep(5000); } catch (InterruptedException e) {}
    System.out.println("Task done");
});

pool.shutdown(); // Stop accepting new tasks
System.out.println(pool.isShutdown()); // true

// Submitting a task after shutdown causes an error
try {
    pool.submit(() -> System.out.println("New task"));
} catch (RejectedExecutionException e) {
    System.out.println("Rejected!");
}

// Wait for termination
try {
    boolean done = pool.awaitTermination(10, TimeUnit.SECONDS);
    System.out.println("All done: " + done);
} catch (InterruptedException e) {}

System.out.println(pool.isTerminated()); // true

