// Deadlock example
Object lockA = new Object();
Object lockB = new Object();

Thread t1 = new Thread(() -> {
    synchronized (lockA) {
        System.out.println("T1: lockA acquired");
        // Operation that may throw an exception
        try { Thread.sleep(100); } catch (InterruptedException e) {}
        synchronized (lockB) { // Waiting for lockB
            System.out.println("T1: lockB acquired");
        }
    }
});

Thread t2 = new Thread(() -> {
    synchronized (lockB) {
        System.out.println("T2: lockB acquired");
        // Operation that may throw an exception
        try { Thread.sleep(100); } catch (InterruptedException e) {}
        synchronized (lockA) { // Waiting for lockA
            System.out.println("T2: lockA acquired");
        }
    }
});

t1.start();
t2.start();
// T1 is waiting for lockB, T2 is waiting for lockA → Deadlock!

// Prevention: Unify the lock acquisition order
// Both threads should acquire lockA → lockB in that order

class SharedData {
    private boolean ready = false;

    public synchronized void waitForReady() throws InterruptedException {
        while (!ready) {  // Checking the condition in a while loop is important
            wait();  // Wait until ready
        }
        System.out.println("Data is ready!");
    }

    public synchronized void setReady() {
        ready = true;
        notifyAll();  // Wake up all waiting threads
    }
}

SharedData data = new SharedData();

Thread waiter = new Thread(() -> {
    try { data.waitForReady(); }
    catch (InterruptedException e) {}
});

Thread setter = new Thread(() -> {
    try { Thread.sleep(1000); } catch (InterruptedException e) {}
    data.setReady();
});

waiter.start();
setter.start();

