import java.util.concurrent.CompletableFuture;

// supplyAsync: with return value
CompletableFuture<String> cf1 = CompletableFuture.supplyAsync(() -> {
    // Executed on a separate thread
    return "Hello from " + Thread.currentThread().getName();
});
System.out.println(cf1.get()); // Hello from ForkJoinPool.commonPool-worker-1

// runAsync: without return value
CompletableFuture<Void> cf2 = CompletableFuture.runAsync(() -> {
    System.out.println("Running in: " + Thread.currentThread().getName());
});
cf2.get(); // Wait for completion

// completedFuture: immediately completed value
CompletableFuture<Integer> cf3 = CompletableFuture.completedFuture(42);
System.out.println(cf3.get()); // 42 (does not block)

// allOf: Wait for all to complete
CompletableFuture<String> cf1 = CompletableFuture.supplyAsync(() -> "Hello");
CompletableFuture<String> cf2 = CompletableFuture.supplyAsync(() -> "World");
CompletableFuture<String> cf3 = CompletableFuture.supplyAsync(() -> "!");

CompletableFuture<Void> all = CompletableFuture.allOf(cf1, cf2, cf3);
all.get(); // Wait until all complete
// Get individual results with get()
System.out.println(cf1.get() + " " + cf2.get() + cf3.get()); // Hello World!

// thenCombine: Combine two results
CompletableFuture<String> combined = CompletableFuture
    .supplyAsync(() -> "Java")
    .thenCombine(
        CompletableFuture.supplyAsync(() -> 17),
        (lang, ver) -> lang + " SE " + ver  // Combine both results
    );
System.out.println(combined.get()); // Java SE 17

// anyOf: Get the first one that completes
CompletableFuture<Object> any = CompletableFuture.anyOf(cf1, cf2);
System.out.println(any.get()); // Either Hello or World

CompletableFuture<String> cf = CompletableFuture
    .supplyAsync(() -> {
        if (true) throw new RuntimeException("Error!");
        return "OK";
    })
    .exceptionally(ex -> "Recovered: " + ex.getMessage());
System.out.println(cf.get()); // Recovered: java.lang.RuntimeException: Error!

// handle: Process both normal and error cases
CompletableFuture<String> handled = CompletableFuture
    .supplyAsync(() -> "Data")
    .handle((result, ex) -> {
        if (ex != null) return "Error";
        return "Success: " + result;
    });
System.out.println(handled.get()); // Success: Data

// getNow: Get default value without blocking
CompletableFuture<String> slow = CompletableFuture.supplyAsync(() -> {
    try { Thread.sleep(5000); } catch (InterruptedException e) {}
    return "Done";
});
System.out.println(slow.getNow("Not ready")); // Not ready

